package com.nexra.hrms.nexra.modules.hrms.performance.entity; import com.nexra.hrms.nexra.modules.hrms.performance.entity.base.AbstractAuditableEntity; import jakarta.persistence.*; import java.math.BigDecimal;
@Entity @Table(name="performance_reviews") public class ReviewEntity extends AbstractAuditableEntity { @Id @Column(name="review_id",nullable=false,length=36) private String reviewId; @Column(name="tenant_code",nullable=false,length=64) private String tenantCode; @Column(name="employee_id",nullable=false,length=36) private String employeeId; @Column(name="review_cycle",nullable=false,length=80) private String reviewCycle; @Column(name="status",nullable=false,length=30) private String status; @Column(name="manager_score",precision=5,scale=2) private BigDecimal managerScore; @Column(name="employee_comments",length=2000) private String employeeComments; @Column(name="manager_comments",length=2000) private String managerComments; public String getReviewId(){return reviewId;} public void setReviewId(final String v){reviewId=v;} public String getTenantCode(){return tenantCode;} public void setTenantCode(final String v){tenantCode=v;} public String getEmployeeId(){return employeeId;} public void setEmployeeId(final String v){employeeId=v;} public String getReviewCycle(){return reviewCycle;} public void setReviewCycle(final String v){reviewCycle=v;} public String getStatus(){return status;} public void setStatus(final String v){status=v;} public BigDecimal getManagerScore(){return managerScore;} public void setManagerScore(final BigDecimal v){managerScore=v;} public String getEmployeeComments(){return employeeComments;} public void setEmployeeComments(final String v){employeeComments=v;} public String getManagerComments(){return managerComments;} public void setManagerComments(final String v){managerComments=v;} }

